var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토, 음료수 받아라.","JPN":"湊、これでも飲めよ。","ENG":"Minato, here is your drink.","TWN":"南裕夏，飲料拿去。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 고마워.","JPN":"ああ、ありがとう。","ENG":"Ah, thanks.","TWN":"喔，謝謝你。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그나저나 신기하네. 다들 피난 얘기를 하고 있는데 아직도 영업하는 편의점이 있다니.","JPN":"それにしても不思議だな。\\nみんなが避難の話をしてるこんな状況で営業してるコンビニがあるなんて。","ENG":"That’s curious. Everyone’s evacuating, but a convenience store is still in business.","TWN":"不過還真奇妙，大家都忙著逃難，怎麼還有便利商店在營業？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아포칼립스라는 상호명이 그냥 멋으로 붙은 건 아니란 거겠지.","JPN":"アポカリプスって名前は伊達じゃないってことなんだろう。","ENG":"I guess it’s called Apocalypse for a reason.","TWN":"知道阿波卡利斯便利商店的厲害了吧！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"라면은 다 익은 것 같은데?","JPN":"カップ麺そろそろ食べごろだぞ。","ENG":"Your cup noodle looks ready.","TWN":"泡麵應該可以吃了吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Okay.","TWN":"嗯。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나야 상관없지만, 마사키 너까지 라면으로 괜찮겠어?","JPN":"僕はいいけど、雅紀までカップ麺でいいの？","ENG":"I’m okay with this, but are you sure you’ll be okay with noodles?","TWN":"我是無所謂，但你可以吃泡麵嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"됐어. 이 새벽에 본부에서 밥 달라고 했다간, 낫토에 된장국이나 먹게 될 게 뻔하니까.","JPN":"ああ。どうせ本部に戻ったってこんな夜明けじゃ\\n納豆にみそ汁程度しか出ないしな。","ENG":"I don’t care. If I ask the Alliance for a meal at this hour, they will feed me fermented beans and soup.","TWN":"只能這樣囉～凌晨跟總部討飯吃，應該只會得到納豆和味噌湯吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하야미 씨는…… 연합에 머물고 있다가 붙잡힌 거지?","JPN":"速水さんは……連合に留まっていて捕まったんだよね？","ENG":"Hayami... They apprehended her while she was staying with the Alliance, right?","TWN":"速水早苗…是停留在聯盟時被逮到的吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래, 재판에 회부되기 전까진 감옥에 가둬 둘 거라고 했어.","JPN":"そうだな。裁判が開かれるまでは拘束するらしい。","ENG":"Yes. They said she will be locked up until the trial.","TWN":"嗯嗯，聽說受審前會先關在監牢裡。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아직도 잘 실감이 나지 않아.","JPN":"まだ信じられないな。","ENG":"I can’t believe it.","TWN":"我到現在還是無法相信。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우릴 치료해줬던 그 사람이 치나츠를 죽이려고 했다니.","JPN":"僕たちを助けてくれた人が千夏を暗殺しようとしたなんて。","ENG":"She saved our lives, yet she tried to kill Chinatsu?","TWN":"那個治療我們的人，竟然想要殺千夏？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"연합 사람들의 관계가 마냥 좋지만은 않다는 건 알고 있었지만…… 이 정도로 심각한 원한이 있는 줄은 몰랐어.","JPN":"連合は複雑な人間関係があることはわかったけど……\\nこんなに深刻だとは思ってなかった。","ENG":"I knew the Alliance members didn’t really get along... but I didn’t expect their grudges to run so deep.","TWN":"我知道聯盟成員間的感情不太好…只是沒想到有這麼大的仇恨。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이제 와서 특별히 이상할 것도 없지.","JPN":"別におかしなことではないんだ。","ENG":"There’s nothing to be surprised about.","TWN":"現在回想起來，其實也沒什麼好奇怪的。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하야미는 원래 나나하라 당주를 지키는 호위무사 가문이었거든.","JPN":"速水家は元々七原家当主を守る護衛の一族だったからな。","ENG":"The Hayami family was traditionally a bodyguard family that protected Nanahara family.","TWN":"速水原本是守護七原堂主的護衛武士家族。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"호위무사? 그건 치나츠의 동생이 맡고 있는 거 아니었어?","JPN":"護衛？　今は千夏の妹がやっているよね？","ENG":"Bodyguard? I thought Chinatsu’s sister was the bodyguard.","TWN":"護衛武士？那不是千夏的妹妹在負責的嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나나하라 가문은 원래 무사를 키우지 않아.","JPN":"七原家は元々武士を育成しない。","ENG":"The Nanahara family is not a warrior clan.","TWN":"七原家族原本是不會培養武士的。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"애초에, 그 무녀 가문에서 쌍둥이가 태어난 것도 역사적으로 전례가 없어.","JPN":"そもそも巫女の家門に双子が生まれたのも歴史的に前例がない。","ENG":"Plus, there had never been twins born to the Nanahara family before.","TWN":"當初，那個巫女家族生出雙胞胎一事，也是史無前例的。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우리가 태어나기도 전에 하야미의 호위무사가 당주를 살해한 사건 이후로 하야미 가문은 유폐됐지.","JPN":"オレたちが生まれる前に速水家の護衛が当主を殺害する事件が起きて、\\n速水家は追放された。","ENG":"Before we were even born, a Hayami bodyguard killed the Alliance leader. Then the Hayami family was expelled from the Alliance.","TWN":"在我們出生之前，速水家族的護衛武士殺害堂主後，速水家族便遭到幽禁。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그렇게 호위무사 자리가 공석이 되자, 치후유가 빈 자리를 맡았을 뿐이야.","JPN":"護衛を任せられる一族が消えたことで、千冬が護衛を引き受けたってわけだ。","ENG":"With the bodyguard family gone, Chifuyu took over the task.","TWN":"護衛武士的位置因而空出來，千冬才去補的。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"언니를 지키기 위해서…… 였던 거구나.","JPN":"お姉さんを守るために……そうしたんだ。","ENG":"So Chifuyu is only doing it to protect her sister.","TWN":"是因為要……保護姊姊嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"잠깐, 그러면 더 말이 안 되지 않아?","JPN":"ちょっと待って、なんかおかしくないか？","ENG":"But... that doesn’t make sense.","TWN":"等一下，那樣不是更奇怪嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 왜 이제 와서 그 사람이 자기 언니의 당주 자리를 맡으려고 하는 건데?","JPN":"じゃあ、どうして今になって姉から当主の座を引き継ごうとしているんだ？","ENG":"She’s been protecting her sister, why would she want to be the family leader after all these years?","TWN":"那她爲什麼現在才想坐上自己姊姊的位子呢？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"글쎄. 단순한 사춘기거나, 우리가 모르는 다른 이유가 있는 거겠지.","JPN":"さあな。単なる思春期か、オレたちにはわからない理由があるんだろ。","ENG":"Maybe she’s going through puberty? Who knows.","TWN":"誰知道！可能是因為叛逆期，或是有我們不知道的原因吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이상해.","JPN":"おかしい。","ENG":"It's weird.","TWN":"真奇怪。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"당연히 이상하지. 이상한 점이 한 두 가지가 아니라고.","JPN":"ああ、本当におかしいことだらけだな。","ENG":"Yeah, everything is weird. I don’t understand a thing about this place.","TWN":"當然奇怪囉，而且奇怪的地方何一兩個。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……하야미 씨가 당주를 살해할 계획이었다면, 왜 진작에 실행에 옮기지 않은 걸까?","JPN":"……速水さんが当主の殺害を企んでいたとしたら、どうして早く実行に移さなかったんだろう？","ENG":"If Hayami was planning to kill the Alliance leader, why didn’t she do it before?","TWN":"……如果速水早苗計劃殺害堂主，那爲何不早點動手呢？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥, 그 여자의 엄마는 호위무사이면서도 선대 당주를 살해했어.","JPN":"フン、あの女の母親は護衛でありながら、先代の当主を殺害したんだぞ。","ENG":"Hmpf, her mother killed the previous Alliance leader, even though she was her bodyguard.","TWN":"哼，那個女人的媽媽身為護衛武士，還不是殺了先祖堂主。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그에 비하면 오히려 그 여자에겐 충분한 동기가 있지. 가령 자기 가문을 내쫓은 것에 대한 보복이라거나.","JPN":"だからあの女には十分動機がある。\\n例えば、一家が追放された事に対する報復とかな。","ENG":"I would say her daughter also has her motives. Revenge for her expelled family, for instance?","TWN":"她比她媽媽更有殺人動機吧！譬如說因為自己的家族遭到驅逐，而懷有報復之心。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그렇지만 하야미 씨가 우리와 함께 연합으로 돌아왔을 때……","JPN":"だけど速水さんが僕たちと一緒に連合に戻った時……","ENG":"But when Hayami came back to the Alliance with us...","TWN":"可是早苗和我們一起回到聯盟時……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"연합에선 사나에란 사람이 살아 있는 줄도 몰랐던 것처럼 당황했잖아.","JPN":"連合のみんなは早苗という人が生きていたことすら\\n知らなかったように驚いていたよね。","ENG":"People were dumbfounded, almost as if they didn’t know she was still alive.","TWN":"聯盟的人都一臉嚇到，似乎連速水早苗還活著的事都不知道。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"암살자를 보낼 생각이었다면, 굳이 연합에 돌아올 필요도 없었을 텐데 말이야.","JPN":"暗殺者を送り込むつもりだったとしたら、\\nあえて連合に戻る必要もなかったはずだ。","ENG":"Why would she come here, if she was going to send assassins?","TWN":"她要派刺客的話，應該沒必要回來聯盟吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐, 그에 대한 이유라면 억지로 가져다 붙일 수도 있겠지만……","JPN":"まあ、それについてはいろいろな可能性がありそうだが……","ENG":"Well, I could make up some rebuttals against that argument...","TWN":"嗯，很可能是硬給她冠上個罪名………"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"확실히 그런 정황은 자연스럽지 못하군.","JPN":"確かに不自然な流れではあるな。","ENG":"But you’re right. That is certainly not natural.","TWN":"確實是有點牽強啦。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하지만.","JPN":"だが。","ENG":"However...","TWN":"可是！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그렇다고 해서 너랑 내가 뭘 어쩌겠어?","JPN":"だからといって、オレとお前で何ができるんだ？","ENG":"What’s the point? There’s nothing we can do.","TWN":"就算如此，我們能怎麼辦嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토 너도, 네 평범한 삶이 남의 일과 엮이는 걸 원하진 않잖아?","JPN":"湊、お前は自分の平凡な人生を捨ててまで\\n他人事に関わることを望んでいないだろう？","ENG":"And you don’t like meddling in someone else’s business that might ruin your ordinary life.","TWN":"南裕夏，你所謂的平凡不就是不插手別人的事嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우릴 도와줬던 은인을 모른 척하지 않는 거.","JPN":"僕たちを助けてくれた恩人を見捨てることはできない。","ENG":"But helping the person who saved our lives...","TWN":"不能對於我們的救命恩人視而不見，"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"충분히 평범한 일이지 않아?","JPN":"これは至って平凡なことだろ？","ENG":"It’s normal, don’t you think?","TWN":"這不就是很平凡的道理嗎？"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토, 너……","JPN":"湊、お前……","ENG":"Minato, you...","TWN":"南裕夏，你……"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"큭큭, 귀찮은 녀석. 하지만 충분히 마음을 울리는 대사였다.","JPN":"クククッ、面倒くせえやつだな。だが、オレ様の胸に十分響く言葉だった。","ENG":"You’re very bothersome, but you know that? What you just said did click with me.","TWN":"呵呵，真會找麻煩。不過這句台詞是很打動人心沒錯！"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"좋아. 오오가미 흑막조가 어둠의 비밀을 파헤칠 때로군.","JPN":"よし。大神黒幕組が闇の秘密を暴く時だな。","ENG":"Alright. It’s the Ogami's Shadow Group’s time for action!","TWN":"很好，黑幕組是時候揭開黑暗的祕密囉！"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그런데, 그 사람이 무고하다고 해도 말이지. 그걸 대체 무슨 수로 입증할 건데?","JPN":"だが本当に速水が無実だとして、それを証明する方法はどうする？","ENG":"But, even if Hayami is innocent, how are you going to prove that?","TWN":"不過就算她是無辜的，那我們要怎麼證明？"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하야미 가문의 본가는 배신자로 낙인 찍힌 뒤로 흔적조차 남지 않았어.","JPN":"速水の本家は裏切者の烙印を押された後、跡形も残らなかった。","ENG":"When the Hayami family were branded as a traitor, any trace of them was removed completely.","TWN":"速水家族被冠上叛徒的罪名後，等於是銷聲匿跡連痕跡。"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"기껏해야 그때 봤던 숲의 작은 오두막이 전부라고.","JPN":"残ってるのはあの時の森の小さな小屋くらいじゃないか。","ENG":"All she has is the little cabin in the woods.","TWN":"頂多就是那時候看到的那個森林小屋。"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 거기로 가보자. 어쩌면 하야미 씨의 알리바이를 입증할 단서가 있을지도 모르잖아?","JPN":"じゃあ、そこに行ってみよう。\\n速水さんの無実を証明できる手がかりがあるかもしれない。","ENG":"Then we’ll go see the cabin. Maybe we’ll find something that might prove her innocence.","TWN":"我們去那裡看看吧！或許可以找到速水早苗的不在場證明。"},"stage":{"bg":"STORE2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};